```tsx title="src/App.tsx"
import { useState } from 'react';
import './styles.css';

const proof = [
  { value: '6 wk', label: 'strength cycle preview' },
  { value: '24/7', label: 'training plan access' },
  { value: '4.9/5', label: 'athlete energy rating' },
];

const features = [
  { title: 'Pulse sessions', body: 'High-output training blocks with enough structure to feel serious without becoming intimidating.' },
  { title: 'Recovery rhythm', body: 'A calmer supporting section balances the neon intensity with mobility, rest, and repeatable progress.' },
  { title: 'Coach-ready preview', body: 'Responsive cards, strong CTA grouping, and a training story that still reads clearly on a phone.' },
];

type ThemeMode = 'dark' | 'light';

export default function App() {
  const [theme, setTheme] = useState<ThemeMode>('dark');
  const [activeFeature, setActiveFeature] = useState(features[0].title);
  const nextTheme = theme === 'dark' ? 'light' : 'dark';
  const themeLabel = theme === 'dark' ? 'Switch to light mode' : 'Switch to dark mode';
  const scrollToId = (id: string) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });

  return (
    <div className={`landing-shell theme-${theme}`}>
      <div className="landing-noise" />
      <header className="topbar">
        <div className="brand-lockup"><span className="brand-mark">K</span><span>kinetic pulse</span></div>
        <nav className="topnav">
          <button type="button" onClick={() => scrollToId('platform')}>Platform</button>
          <button type="button" onClick={() => scrollToId('live-proof')}>Preview</button>
          <button type="button" onClick={() => scrollToId('release-flow')}>Flow</button>
          <button type="button" onClick={() => scrollToId('launch-cta')}>Launch</button>
        </nav>
        <div className="topbar-actions">
          <button type="button" className="theme-toggle" aria-label={themeLabel} title={theme === 'dark' ? 'Light mode' : 'Dark mode'} onClick={() => setTheme(nextTheme)}>
            {theme === 'dark' ? (
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="4" />
                <path d="M12 2v2.5M12 19.5V22M4.93 4.93l1.77 1.77M17.3 17.3l1.77 1.77M2 12h2.5M19.5 12H22M4.93 19.07l1.77-1.77M17.3 6.7l1.77-1.77" />
              </svg>
            ) : (
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <path d="M21 12.79A9 9 0 1 1 11.21 3A7 7 0 0 0 21 12.79Z" />
              </svg>
            )}
          </button>
          <button className="ghost-button">View programs</button>
        </div>
      </header>

      <main className="hero-grid" id="platform">
        <section className="hero-panel" id="live-proof">
          <p className="eyebrow">Neon performance training</p>
          <h1>kinetic pulse</h1>
          <p className="lede">A dark, neon fitness landing page for athletes who want sharp programming, visible momentum, and a training flow that feels ready to start.</p>
          <div className="hero-actions">
            <button className="primary-button" type="button" onClick={() => scrollToId('launch-cta')}>start training</button>
            <button className="secondary-button" type="button" onClick={() => { setActiveFeature(features[0].title); scrollToId('release-flow'); }}>Explore the training flow</button>
          </div>
          <div className="proof-strip">
            {proof.map((item) => (
              <article key={item.label}>
                <strong>{item.value}</strong>
                <span>{item.label}</span>
              </article>
            ))}
          </div>
        </section>

        <aside className="signal-panel">
          <p className="signal-label">Why it feels better</p>
          <h2>Electric energy, clear programs, and a CTA that feels ready to move.</h2>
          <p>The page keeps the fitness promise visible: powerful headline, performance proof, and direct training actions without burying the user in generic marketing copy.</p>
          <div className="signal-rail">
            <span>Neon dark shell</span>
            <span>Training-first CTA</span>
            <span>Mobile workout flow</span>
          </div>
        </aside>
      </main>

      <section className="feature-grid" id="release-flow">
        {features.map((feature) => (
          <article key={feature.title} className={`feature-card ${activeFeature === feature.title ? 'feature-card-active' : ''}`} onMouseEnter={() => setActiveFeature(feature.title)}>
            <p className="feature-kicker">Flow</p>
            <h3>{feature.title}</h3>
            <p>{feature.body}</p>
          </article>
        ))}
      </section>

      <section className="cta-panel" id="launch-cta">
        <div><p className="eyebrow">Ready to move</p><h2>Turn intent into the next training block.</h2></div>
        <form className="cta-form">
          <input type="email" placeholder="athlete@email.com" />
          <button type="button" className="primary-button">start training</button>
        </form>
      </section>
    </div>
  );
}
